"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchPolicyAnalysis } from "@/lib/api";
import type { PolicyInfo } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";
import { ArrowLeft, Sparkles, TrendingUp, TrendingDown, Minus, ExternalLink } from "lucide-react";

export default function PolicyDetailPage() {
  const { id } = useParams<{ id: string }>();
  const [data, setData] = useState<PolicyInfo | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    fetchPolicyAnalysis(id)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [id]);

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <Link href="/policy" className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors">
        <ArrowLeft className="w-4 h-4 mr-1" /> 목록으로
      </Link>

      {loading && <LoadingSpinner text="AI가 정책을 분석하고 있어요..." />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <>
          {/* 이미지 */}
          {data.image_url && (
            <div className="rounded-xl overflow-hidden">
              <img src={data.image_url} alt="" className="w-full h-56 object-cover" />
            </div>
          )}

          <div>
            <p className="text-sm text-purple-400 mb-1">{data.department}</p>
            <h1 className="text-2xl font-bold">{data.title}</h1>
            <p className="text-gray-300 mt-3">{data.description}</p>
            <div className="flex items-center gap-4 mt-2">
              {data.effective_date && (
                <p className="text-sm text-gray-500">시행일: {data.effective_date}</p>
              )}
              {data.link && (
                <a
                  href={data.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-sm text-skyblue hover:underline flex items-center gap-1"
                >
                  <ExternalLink className="w-3.5 h-3.5" /> 원문 보기
                </a>
              )}
            </div>
          </div>

          {/* AI 분석 */}
          <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5">
            <div className="flex items-center gap-2 mb-3">
              <Sparkles className="w-5 h-5 text-skyblue" />
              <h2 className="font-bold text-skyblue">AI 정책 분석</h2>
            </div>
            <p className="text-gray-200 leading-relaxed whitespace-pre-line">{data.ai_analysis}</p>
          </div>

          {/* 수혜주 */}
          {data.beneficiary_stocks?.length > 0 && (
            <div>
              <h2 className="text-lg font-bold mb-3">수혜/피해 종목</h2>
              <div className="space-y-2">
                {data.beneficiary_stocks.map((s, i) => {
                  const Icon = s.impact === "positive" ? TrendingUp : s.impact === "negative" ? TrendingDown : Minus;
                  const color = s.impact === "positive" ? "text-green-400" : s.impact === "negative" ? "text-red-400" : "text-gray-400";
                  return (
                    <Link
                      key={i}
                      href={`/stock/${s.stock_code}`}
                      className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors"
                    >
                      <div className="flex justify-between items-center">
                        <div className="flex items-center gap-3">
                          <Icon className={`w-5 h-5 ${color}`} />
                          <div>
                            <p className="font-medium">{s.stock_name}</p>
                            <p className="text-xs text-gray-400">{s.stock_code}</p>
                          </div>
                        </div>
                        <p className="text-sm text-gray-300 text-right max-w-[50%]">{s.reason}</p>
                      </div>
                    </Link>
                  );
                })}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
